  ('dietitian-moex-11614', 'dietitian', 'dietitian-moex-092-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', 'D W是指10% 的： 10 葡萄糖溶液  脂肪乳劑  胺基酸溶液  甘油溶液', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:59+00:00", "source_pdf_sha1": "c2fd7358752e", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "092170", "c": "111", "s": "3001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "膳食療養學", "year": "092", "exam_name": "092年第二次醫事人員、中醫師、營養師、獸醫人員、心理師、呼吸治療師考試", "original_question_number": 5, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-11615', 'dietitian', 'dietitian-moex-092-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '依據衛生署公布資料（民國九十一年），我國成人身體質量指數 (Body mass index, BMI) 的正常值應為： 15~18.4  18.5~23.9  24~26.9  27~29.9', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:59+00:00", "source_pdf_sha1": "c2fd7358752e", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "092170", "c": "111", "s": "3001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "膳食療養學", "year": "092", "exam_name": "092年第二次醫事人員、中醫師、營養師、獸醫人員、心理師、呼吸治療師考試", "original_question_number": 6, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-11616', 'dietitian', 'dietitian-moex-092-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '當病患採用高纖維飲食時，下列那一項是最重要的？ 每日攝取足夠水分    增加鐵的攝取 增加葉酸的攝取    增加多元不飽和脂肪酸的攝取', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:59+00:00", "source_pdf_sha1": "c2fd7358752e", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "092170", "c": "111", "s": "3001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "膳食療養學", "year": "092", "exam_name": "092年第二次醫事人員、中醫師、營養師、獸醫人員、心理師、呼吸治療師考試", "original_question_number": 7, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-11617', 'dietitian', 'dietitian-moex-092-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '用餐時，下列何種食物成分攝取過多時，會加重傾食徵候群之症狀？ 醣類；水分  蛋白質；脂質  蛋白質；水分  醣類；脂質', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:59+00:00", "source_pdf_sha1": "c2fd7358752e", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "092170", "c": "111", "s": "3001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "膳食療養學", "year": "092", "exam_name": "092年第二次醫事人員、中醫師、營養師、獸醫人員、心理師、呼吸治療師考試", "original_question_number": 8, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-11618', 'dietitian', 'dietitian-moex-092-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '下列與減重相關的知識，何者正確？ 每天減少500~1000大卡，每週可減2~3磅  以飲食控制再配合運動是適當的減重方式 單靠節食即可有效減少脂肪組織  節食會影響基礎代謝率，使熱量消耗增加', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:59+00:00", "source_pdf_sha1": "c2fd7358752e", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "092170", "c": "111", "s": "3001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "膳食療養學", "year": "092", "exam_name": "092年第二次醫事人員、中醫師、營養師、獸醫人員、心理師、呼吸治療師考試", "original_question_number": 9, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-11619', 'dietitian', 'dietitian-moex-092-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '下列有關肥胖的敘述，何者正確？ 蘋果型肥胖較梨型肥胖有更高的慢性病罹患率 血脂肪與尿酸升高與體重過重無關 肥胖者血氧濃度常處於偏高狀態，可能發生睡眠呼吸中斷症 1公斤的骨骼肌或肝醣組織約相當1500大卡', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:59+00:00", "source_pdf_sha1": "c2fd7358752e", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "092170", "c": "111", "s": "3001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "膳食療養學", "year": "092", "exam_name": "092年第二次醫事人員、中醫師、營養師、獸醫人員、心理師、呼吸治療師考試", "original_question_number": 10, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-11620', 'dietitian', 'dietitian-moex-092-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '以下關於食物熱能效應 (DIT) 之敘述，何者不正確？ 每日熱量之消耗包括休息時之代謝率 (RMR) + DIT + 活動量 對同一人而言吃宵夜時之DIT較吃午點時為高 DIT越高減重效果越佳 食物之組成、餐量大小均影響DIT之大小', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:59+00:00", "source_pdf_sha1": "c2fd7358752e", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "092170", "c": "111", "s": "3001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "膳食療養學", "year": "092", "exam_name": "092年第二次醫事人員、中醫師、營養師、獸醫人員、心理師、呼吸治療師考試", "original_question_number": 11, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-11621', 'dietitian', 'dietitian-moex-092-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '當病人接受腸道營養灌食而引起腹瀉，下列何項處置較不適當？ 改成無乳糖配方  將灌食速度調慢  改善過低的血清白蛋白  將灌食加熱', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:59+00:00", "source_pdf_sha1": "c2fd7358752e", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "092170", "c": "111", "s": "3001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "膳食療養學", "year": "092", "exam_name": "092年第二次醫事人員、中醫師、營養師、獸醫人員、心理師、呼吸治療師考試", "original_question_number": 12, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-11622', 'dietitian', 'dietitian-moex-092-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '當橫膈附近肌肉變弱或喪失肌肉張力，使胃突出於橫膈之上的症狀稱為： 食道迴流 (Esophageal reflux)  食道裂孔突出 (Hiatus hernia) 胃輕癱 (Gastroparesis)    弛緩不能 (Achalasia) （請接背面） 九十二年第二次專門職業及技術人員高等暨普通考試醫事人員考試、高等考試 全一張 中醫師考試、高等考試營養師考試、高等暨普通考試獸醫人員考試及九十二年 代號：11130 （背面） 專門職業及技術人員高等考試心理師考試、高等考試呼吸治療師考試試題 類    科： 營養師', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:59+00:00", "source_pdf_sha1": "c2fd7358752e", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "092170", "c": "111", "s": "3001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "膳食療養學", "year": "092", "exam_name": "092年第二次醫事人員、中醫師、營養師、獸醫人員、心理師、呼吸治療師考試", "original_question_number": 13, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-11623', 'dietitian', 'dietitian-moex-092-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '對於弛緩不能 (Achalasia) 之病患應避免： 少量多餐  液狀食物  冰冷的食物  軟質食物', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:59+00:00", "source_pdf_sha1": "c2fd7358752e", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "092170", "c": "111", "s": "3001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "膳食療養學", "year": "092", "exam_name": "092年第二次醫事人員、中醫師、營養師、獸醫人員、心理師、呼吸治療師考試", "original_question_number": 14, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL)
